(function(){
function initShopSlider(slider){
  if(slider.getAttribute("data-fq-shop-slider-init")==="1"){return}
  slider.setAttribute("data-fq-shop-slider-init","1");
  var slides=slider.querySelectorAll("[data-fq-shop-slide]");
  if(slides.length<2){return}
  var prev=slider.querySelector("[data-fq-shop-prev]");
  var next=slider.querySelector("[data-fq-shop-next]");
  var index=0;var timer=null;
  var show=function(n){slides[index].classList.remove("is-active");index=(n+slides.length)%slides.length;slides[index].classList.add("is-active")};
  var restart=function(){if(timer){clearInterval(timer)}timer=setInterval(function(){show(index+1)},5000)};
  if(prev){prev.addEventListener("click",function(){show(index-1);restart()})}
  if(next){next.addEventListener("click",function(){show(index+1);restart()})}
  restart()
}

function injectShopSlider(){
  var source=document.querySelector("[data-fq-shop-slider-source]");
  if(!source){return}
  // Solo el primer sp-filter-products-container
  var container=document.querySelector(".sp-filter-products-container");
  if(!container){return}
  if(container.querySelector("[data-fq-shop-slider]")){return}
  var productsList=container.querySelector("#sp-filter-products-list");
  var slider=source.firstElementChild;
  if(!slider){return}
  var clone=slider.cloneNode(true);
  if(productsList){container.insertBefore(clone,productsList)}else{container.insertBefore(clone,container.firstChild)}
  initShopSlider(clone)
}

var observer=new MutationObserver(function(){injectShopSlider()});
function start(){
  observer.observe(document.body,{childList:true,subtree:true});
  injectShopSlider()
}
if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",start)}else{start()}
})();
